"use client";

import { useEffect, useMemo, useState } from "react";

import styles from "./ArtifactViewer.module.css";
import { loadArtifactViewerModelFromApi } from "./api-client";
import {
  filterArtifactDocuments,
  type ArtifactDocumentView,
  type ArtifactViewerModel,
} from "./model";

type ArtifactViewerProps = {
  readonly model: ArtifactViewerModel | null;
  readonly runId?: string | null;
};

export function ArtifactViewer({ model, runId = null }: ArtifactViewerProps) {
  const [query, setQuery] = useState("");
  const [selectedDocumentId, setSelectedDocumentId] = useState<string | null>(
    null,
  );
  const [remoteModel, setRemoteModel] = useState<ArtifactViewerModel | null>(
    null,
  );
  const [loadState, setLoadState] = useState<
    "idle" | "loading" | "loaded" | "error"
  >("idle");
  const effectiveModel = model ?? remoteModel;
  const documents = useMemo(
    () =>
      effectiveModel === null
        ? []
        : filterArtifactDocuments(effectiveModel.documents, query),
    [effectiveModel, query],
  );
  const selected =
    documents.find((document) => document.id === selectedDocumentId) ??
    documents[0] ??
    null;

  useEffect(() => {
    if (model !== null || runId === null) {
      return;
    }

    const controller = new AbortController();
    setLoadState("loading");
    setRemoteModel(null);

    void loadArtifactViewerModelFromApi(runId, {
      signal: controller.signal,
    }).then(
      (loaded) => {
        if (!controller.signal.aborted) {
          setRemoteModel(loaded);
          setLoadState("loaded");
        }
      },
      () => {
        if (!controller.signal.aborted) {
          setRemoteModel(null);
          setLoadState("error");
        }
      },
    );

    return () => controller.abort();
  }, [model, runId]);

  if (effectiveModel === null) {
    return (
      <section className={styles.empty} aria-label="Artifact viewer">
        <h2>Artifacts</h2>
        <p>{artifactEmptyMessage(loadState, runId)}</p>
      </section>
    );
  }

  return (
    <section className={styles.viewer} aria-label="Artifact viewer">
      <div className={styles.header}>
        <div>
          <h2>Artifacts</h2>
          <p>
            Run {effectiveModel.runId} · {effectiveModel.modelId} · seed{" "}
            {effectiveModel.seed}
          </p>
        </div>
        <label className={styles.search}>
          <span>Search</span>
          <input
            value={query}
            onChange={(event) => {
              setQuery(event.target.value);
              setSelectedDocumentId(null);
            }}
          />
        </label>
      </div>

      <div className={styles.layout}>
        <div className={styles.tree} aria-label="Generation tree">
          {effectiveModel.floors.map((floor) => (
            <section
              className={[
                styles.floor,
                floor.fallback ? styles.fallback : "",
              ]
                .filter(Boolean)
                .join(" ")}
              data-fallback={floor.fallback ? "true" : "false"}
              key={floor.id}
            >
              <button
                type="button"
                onClick={() => setSelectedDocumentId(`record:${floor.depth}`)}
              >
                <span>Floor {floor.depth}</span>
                <strong>{floor.outcomeLabel}</strong>
              </button>
              <ol>
                {floor.attempts.map((attempt) => (
                  <li key={attempt.id}>
                    <button
                      type="button"
                      onClick={() =>
                        setSelectedDocumentId(
                          attempt.manifestPath === null
                            ? `raw:${floor.depth}:${attempt.attemptIndex}`
                            : `manifest:${floor.depth}:${attempt.attemptIndex}`,
                        )
                      }
                    >
                      <span>{attempt.label}</span>
                      <em>{attempt.providerOk ? "provider ok" : "provider failed"}</em>
                    </button>
                    <div className={styles.usage}>
                      {attempt.latencyLine} · {attempt.usageLine}
                    </div>
                    <div className={styles.paths}>
                      <code>{attempt.rawOutputPath}</code>
                      {attempt.manifestPath === null ? null : (
                        <code>{attempt.manifestPath}</code>
                      )}
                    </div>
                    {attempt.gateSummaries.length === 0 ? null : (
                      <ul className={styles.gates}>
                        {attempt.gateSummaries.map((gate) => (
                          <li
                            className={gate.pass ? styles.gatePass : styles.gateFail}
                            key={`${attempt.id}:${gate.gate}`}
                          >
                            <button
                              type="button"
                              onClick={() =>
                                setSelectedDocumentId(
                                  `gate:${floor.depth}:${attempt.attemptIndex}:${gate.gate}`,
                                )
                              }
                            >
                              <span>{gate.label}</span>
                              <strong>{gate.pass ? "PASS" : "FAIL"}</strong>
                            </button>
                            <p>{gate.summary}</p>
                          </li>
                        ))}
                      </ul>
                    )}
                  </li>
                ))}
              </ol>
            </section>
          ))}
        </div>

        <DocumentPane document={selected} resultCount={documents.length} />
      </div>
    </section>
  );
}

const artifactEmptyMessage = (
  loadState: "idle" | "loading" | "loaded" | "error",
  runId: string | null,
): string => {
  if (loadState === "loading") {
    return "Loading generation artifacts...";
  }

  if (loadState === "error") {
    return "Artifact records are unavailable; fallback play remains intact.";
  }

  return runId === null
    ? "No generation artifacts selected."
    : "No generation artifacts recorded for this run; fallback play remains intact.";
};

function DocumentPane({
  document,
  resultCount,
}: {
  readonly document: ArtifactDocumentView | null;
  readonly resultCount: number;
}) {
  const [copiedId, setCopiedId] = useState<string | null>(null);

  if (document === null) {
    return (
      <div className={styles.document} aria-label="Artifact document">
        <div className={styles.noDocument}>No matching artifacts</div>
      </div>
    );
  }

  return (
    <article
      className={[
        styles.document,
        document.fallback ? styles.fallbackDocument : "",
      ]
        .filter(Boolean)
        .join(" ")}
      aria-label="Artifact document"
      data-fallback={document.fallback ? "true" : "false"}
    >
      <header>
        <div>
          <h3>{document.title}</h3>
          <p>
            {resultCount} document{resultCount === 1 ? "" : "s"}
            {document.path === null ? "" : ` · ${document.path}`}
          </p>
        </div>
        <button
          type="button"
          data-copy-text={document.pretty}
          onClick={() => {
            setCopiedId(document.id);
            void navigator.clipboard?.writeText(document.pretty);
          }}
        >
          {copiedId === document.id ? "Copied" : "Copy"}
        </button>
      </header>
      <pre>{document.pretty}</pre>
    </article>
  );
}

"use client";

import type { DungeonDiary } from "@harness/diary";

import { ArtifactViewer } from "@/components/artifacts/ArtifactViewer";
import type { ArtifactViewerModel } from "@/components/artifacts/model";

import { DiaryPanel } from "./DiaryPanel";
import styles from "./DiaryLayer.module.css";

export type DiaryLayerTab = "diary" | "artifacts";

type DiaryLayerProps = {
  readonly diary: DungeonDiary;
  readonly artifactModel: ArtifactViewerModel | null;
  readonly artifactRunId?: string | null;
  readonly activeTab: DiaryLayerTab;
  readonly onSelectTab: (tab: DiaryLayerTab) => void;
  readonly onClose: () => void;
};

export function DiaryLayer({
  diary,
  artifactModel,
  artifactRunId = null,
  activeTab,
  onSelectTab,
  onClose,
}: DiaryLayerProps) {
  return (
    <div
      className={styles.scrim}
      aria-label="Diary and artifacts layer"
      data-testid="diary-layer"
    >
      <section className={styles.layer} role="dialog" aria-modal="false">
        <header className={styles.header}>
          <div>
            <h2>The Deep's manuscript</h2>
            <p>
              Floor {diary.summary.depth} · turn {diary.summary.turns}
            </p>
          </div>
          <div className={styles.controls}>
            <div className={styles.tabs} role="tablist" aria-label="Second layer tabs">
              <button
                type="button"
                role="tab"
                aria-selected={activeTab === "diary"}
                data-selected={activeTab === "diary" ? "true" : "false"}
                data-testid="diary-tab"
                onClick={() => onSelectTab("diary")}
              >
                Diary
              </button>
              <button
                type="button"
                role="tab"
                aria-selected={activeTab === "artifacts"}
                data-selected={activeTab === "artifacts" ? "true" : "false"}
                data-testid="artifacts-tab"
                onClick={() => onSelectTab("artifacts")}
              >
                Artifacts
              </button>
            </div>
            <button className={styles.close} type="button" onClick={onClose}>
              Close
            </button>
          </div>
        </header>

        <div className={styles.content}>
          {activeTab === "diary" ? (
            <DiaryPanel diary={diary} variant="partial" />
          ) : (
            <ArtifactViewer model={artifactModel} runId={artifactRunId} />
          )}
        </div>
      </section>
    </div>
  );
}

import { createElement } from "react";
import { renderToStaticMarkup } from "react-dom/server";
import { describe, expect, it } from "vitest";

import {
  MemoryArtifactFs,
  type GenerationRecord,
  type RunGenerationIndex,
} from "@harness/artifacts";

import { readArtifactsRoute } from "@/api/artifacts/route-core";

import { ArtifactViewer } from "./ArtifactViewer";
import { loadArtifactViewerModelFromApi } from "./api-client";
import {
  filterArtifactDocuments,
  reachableArtifactPaths,
} from "./model";
import { loadArtifactViewerModel } from "./reader";

describe("ArtifactViewer", () => {
  it("makes every persisted floor artifact reachable through the reader-backed model", () => {
    const fs = fixtureArtifactFs();
    const model = loadArtifactViewerModel(RUN_ID, { fs, rootDir: "runs" });

    expect(reachableArtifactPaths(model)).toEqual([
      "floors/1/attempts/0/raw.txt",
      "floors/1/attempts/1/manifest.json",
      "floors/1/attempts/1/raw.txt",
      "floors/1/generation.json",
    ]);
    expect(model.floors[0]?.fallback).toBe(true);
    expect(model.floors[0]?.attempts).toHaveLength(2);
    expect(model.documents.map((document) => document.kind)).toContain("gate");
  });

  it("renders tree, readable gate reasons, usage/latency, pretty JSON, search, copy, and fallback highlight", () => {
    const model = loadArtifactViewerModel(RUN_ID, {
      fs: fixtureArtifactFs(),
      rootDir: "runs",
    });
    const markup = renderToStaticMarkup(createElement(ArtifactViewer, { model }));

    expect(markup).toContain("Generation tree");
    expect(markup).toContain("Repair attempt 1");
    expect(markup).toContain("Latency 42ms");
    expect(markup).toContain("Tokens 30 (10 in / 20 out)");
    expect(markup).toContain("Gate 0 failed");
    expect(markup).toContain("G0_INVALID_JSON");
    expect(markup).toContain('data-fallback="true"');
    expect(markup).toContain("Copy");
    expect(markup).toContain("{\n");

    const filtered = filterArtifactDocuments(model.documents, "invalid JSON");
    expect(filtered.map((document) => document.kind)).toContain("gate");
  });

  it("renders a presentable empty state for runs without artifacts", () => {
    const markup = renderToStaticMarkup(
      createElement(ArtifactViewer, { model: null, runId: "missing-run" }),
    );

    expect(markup).toContain("No generation artifacts recorded for this run");
    expect(markup).toContain("fallback play remains intact");
  });

  it("loads the Tab artifact pane model through the read-only API bridge", async () => {
    const fs = fixtureArtifactFs();
    const listResult = readArtifactsRoute("http://localhost/api/artifacts", {
      fs,
      rootDir: "runs",
    });
    const loadResult = readArtifactsRoute(
      `http://localhost/api/artifacts?runId=${encodeURIComponent(RUN_ID)}`,
      { fs, rootDir: "runs" },
    );
    const unsafeResult = readArtifactsRoute(
      "http://localhost/api/artifacts?runId=../secret",
      { fs, rootDir: "runs" },
    );

    expect(listResult.status).toBe(200);
    expect(
      listResult.payload.ok && listResult.payload.action === "list"
        ? listResult.payload.runs.map((run) => run.runId)
        : [],
    ).toEqual([RUN_ID]);
    expect(loadResult.status).toBe(200);
    expect(unsafeResult.status).toBe(400);
    if (!loadResult.payload.ok || loadResult.payload.action !== "load") {
      throw new Error("fixture artifact bridge did not load the run model");
    }

    const fetched = await loadArtifactViewerModelFromApi(RUN_ID, {
      fetcher: async () =>
        new Response(JSON.stringify(loadResult.payload), {
          status: loadResult.status,
          headers: { "content-type": "application/json" },
        }),
    });
    const markup = renderToStaticMarkup(
      createElement(ArtifactViewer, { model: fetched }),
    );

    expect(fetched?.runId).toBe(RUN_ID);
    expect(markup).toContain("Repair attempt 1");
    expect(markup).toContain("Gate 0 failed");
  });
});

const RUN_ID = "run-artifact-viewer";
